modifier onlyOwner() {
    require(owner() == _msgSender(), "Ownable: caller is not the owner");
    _;
}

function recoverERC20(address _token, uint256 _amount) external {
    require(_amount > 0, "ZERO_RECOVERY_AMOUNT");

    emit ERC20Recovered(msg.sender, _token, _amount);

    IERC20(_token).safeTransfer(TREASURY, _amount);
}

modifier onlyOwner() {
    if (msg.sender != _owner) {
        revert OwnableUnauthorized();
    }
    _;
}

function recoverERC721(IERC721 _token, uint256 _tokenId) external {
    emit ERC721Recovered(msg.sender, address(_token), _tokenId);

    _token.transferFrom(address(this), TREASURY, _tokenId);
}

constructor(uint256 secondsPerSlot, uint256 genesisTime) {
    if (secondsPerSlot == 0) revert SecondsPerSlotCannotBeZero();
    SECONDS_PER_SLOT = secondsPerSlot;
    GENESIS_TIME = genesisTime;
}

function supportsInterface(bytes4 interfaceId) public view virtual override(CreatorCore, IERC165) returns (bool) {
    return interfaceId == type(IERC721CreatorCore).interfaceId || interfaceId == _ERC721_CREATOR_CORE_V1
        || super.supportsInterface(interfaceId);
}

function supportsInterface(bytes4 interfaceId) public view virtual override(ERC165, IERC165) returns (bool) {
    return interfaceId == type(IERC721).interfaceId || interfaceId == type(IERC721Metadata).interfaceId
        || super.supportsInterface(interfaceId);
}

function _domainSeparatorV4() internal view returns (bytes32) {
    return _buildDomainSeparator();
}

function _buildDomainSeparator() private view returns (bytes32) {
    return keccak256(abi.encode(TYPE_HASH, _EIP712NameHash(), _EIP712VersionHash(), block.chainid, address(this)));
}

function initialize() public initializer {
    __ERC721_init("Example", "EXAMPLE");
    __ERC2981_init();
    __Ownable_init();
    __DefaultOperatorFilterer_init();
}

for (uint256 i = 0; i < tokenIdsLength; ++i) {
    address chipAddress = chipAddresses[i];
    uint256 tokenId = tokenIds[i];
    if (throwIfTokenAlreadyMinted && _exists(tokenId)) {
        revert SeedingChipDataForExistingToken();
    }
    _tokenDatas[chipAddress] = TokenData(tokenId, chipAddress, true);
}

return _interfaceId == type(IDeleGatorCore).interfaceId || _interfaceId == type(IERC721Receiver).interfaceId
            || _interfaceId == type(IERC1155Receiver).interfaceId || _interfaceId == type(IERC165).interfaceId
            || _interfaceId == type(IERC1271).interfaceId;

MoonwellERC4626 usdcVault = new MoonwellERC4626(
    ERC20(addresses.getAddress("USDBC")),
    MErc20(addresses.getAddress("MOONWELL_USDBC")),
    rewardReceiver,
    IComptroller(addresses.getAddress("UNITROLLER"))
);

for (uint256 i; i < nBlobs; ++i) {
    blobhashes[i] = blobhash(blobIndices[i]);
    require(blobhashes[i] != 0, "Blob not found");
}

if (useSafeTransferFrom) {
    _safeTransfer(ownerOf(tokenId), _msgSender(), tokenId, "");
} else {
    _transfer(ownerOf(tokenId), _msgSender(), tokenId);
}

if (useSafeTransfer) {
    _safeTransfer(ownerOf(tokenId), to, tokenId, "");
} else {
    _transfer(ownerOf(tokenId), to, tokenId);
}

if (pos > 0 && ckpts[pos - 1].fromBlock == block.number) {
    ckpts[pos - 1].votes = SafeCast.toUint224(newWeight);
} else {
    ckpts.push(Checkpoint({
        fromBlock: SafeCast.toUint32(block.number),
        votes: SafeCast.toUint224(newWeight)
    }));
}

DOMAIN_SEPARATOR = keccak256(
    abi.encodePacked(
        EIP712_DOMAIN_TYPEHASH,
        keccak256(bytes(DOMAIN_NAME))
    )
);

if (liquidity > 0) {
    (uint256 burned0, uint256 burned1, uint256 fees0, uint256 fees1) =
        _burnAndCollect(tickLower, tickUpper, _toUint128(liquidity));

    // Add share of fees
    amount0 = burned0.add(fees0.mul(shares).div(totalSupply));
    amount1 = burned1.add(fees1.mul(shares).div(totalSupply));
}

function confirmingRoles() public pure returns (bytes32[] memory roles) {
    roles = new bytes32[](2);
    roles[0] = DEFAULT_ADMIN_ROLE;
    roles[1] = NODE_OPERATOR_MANAGER_ROLE;
}

function createGate(bytes32 merkleRoot) external returns (bytes12 id) {
    uint96 id_ = ++_lastId;
    merkleRoots[id_] = merkleRoot;
    id = bytes12(id_);
}

for (uint256 i = 0; i < chipAddresses.length; ++i) {
    address chipAddress = chipAddresses[i];
    _tokenDatas[chipAddress] = TokenData(0, chipAddress, false);
}

while (value != 0) {
    digits -= 1;
    buffer[digits] = bytes1(uint8(48 + uint256(value % 10)));
    value /= 10;
}

for (uint256 i; i < balance; i++) {
  uint256 estateId = ownedTokens[_owner][i];
  landsSize += estateLandIds[estateId].length;
}

for (uint256 i = 0; i < nodeSupportedModels[nodeId].length(); i++) {
    uint256 modelId = nodeSupportedModels[nodeId].at(i);
    delete nodeModelConfigs[nodeId][modelId];
    modelSupportingNodes[modelId].remove(nodeId);
}

if (creator != address(0)) {
    creatorFeeAmount = (STANDARD_ROYALTY_FEE_BP * price) / ONE_HUNDRED_PERCENT_IN_BP;
}

for (uint256 x = 0; x < numberOfTokens; x++) {
    if (!accountLiquidated(tokenOfOwnerByIndex(userAddress, x))) {
        temp[numberOfActive] = tokenOfOwnerByIndex(userAddress, x);
        numberOfActive++;
    }
}

for (uint256 i = 0; i < numberRoots; i++) {
  bytes storage root = offchainStorageRoots[account][i];
  lengths[i] = root.length;
  for (uint256 j = 0; j < lengths[i]; j++) {
    concatenated[lastIndex] = root[j];
    lastIndex++;
  }
}

if (currentBalance >= amountGoal) {
    state = State.Successful;
    payOut();
} else if (now > raiseBy)  {
    state = State.Expired;
}

require(
  feesCollectorCutPerMillion + royaltiesCutPerMillion < 1000000,
  "MarketplaceV2#setFeesCollectorCutPerMillion: TOTAL_FEES_MUST_BE_BETWEEN_0_AND_999999"
);

require(
  feesCollectorCutPerMillion + royaltiesCutPerMillion < 1000000,
  "MarketplaceV2#setRoyaltiesCutPerMillion: TOTAL_FEES_MUST_BE_BETWEEN_0_AND_999999"
);

require(
  nftRegistry.supportsInterface(ERC721_Interface),
  "MarketplaceV2#_requireERC721: INVALID_ERC721_IMPLEMENTATION"
);

if (msg.sender != _from) {
    for (uint256 i = 0; i < _ids.length; ++i) {
        allowances[_from][msg.sender][_ids[i]] = allowances[_from][msg.sender][_ids[i]].sub(_values[i]);
    }
}

for (uint256 i = 0; i < _owners.length; ++i) {
    uint256 id = _ids[i];
    if (isNonFungibleItem(id)) {
        balances_[i] = nfOwners[id] == _owners[i] ? 1 : 0;
    } else {
    	balances_[i] = balances[id][_owners[i]];
    }
}

return super._supportsInterface(_interfaceId)
      || _interfaceId == InterfaceId_GetMetadata
      || _interfaceId == InterfaceId_VerifyFingerprint;

if (_interfaceId == INTERFACE_SIGNATURE_ERC165 ||
             _interfaceId == INTERFACE_SIGNATURE_ERC1155) {
            return true;
         }

if (_to.isContract()) {
    _doSafeTransferAcceptanceCheck(msg.sender, _from, _to, _id, _value, _data);
}

for (uint256 i = 0; i < selectors.length; ++i) {
    _setRequirements(target, selectors[i], mask);
}

if(callChain) {
    ContextUpgradable.__init(false);
    ERC20DetailedUpgradable.__init(false, "Gold", "GLD", 18);
}

for (uint256 i = 0; i < EnumerableSet.length(activeTokens); i++) {
  address token = activeTokens.get(i);
  _distribute(token);
}

for (uint256 i = 0; i < tokenAddresses.length; i++) {
  _setMinimumReports(tokenAddresses[i], newMinimumReports[i]);
}

if (selector_ == _PERMIT2_INVALIDATE_NONCES_SELECTOR) {
    require(
        flags_ & _PERMISSION_PERMIT2_INVALIDATE_NONCES != 0,
        "ApprovalRevocationEnforcer:permit2-invalidate-nonces-not-allowed"
    );
    require(target_ == _PERMIT2, "ApprovalRevocationEnforcer:invalid-permit2-target");
    return;
}

return tA == 0
            ? assets
            : tS.fromUint().mul(PRBMathUD60x18.div(tA + assets, tA).pow(BUY_CURVE_PARAM)).toUint() - tS;

uint256 numerator = getValidators().getGroupNumMembers(group).add(1).mul(
  getLockedGold().getTotalLockedGold()
);

uint256 right = getValidators().getGroupNumMembers(group).add(1).mul(
  getLockedGold().getTotalLockedGold()
);
